import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { login } from '../api/api';
import LanguageSwitcher from './LanguageSwitcher';

function Login({ switchToSignup, onLogin }) {
  const { t } = useTranslation();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleLogin = async () => {
    if (!email || !password) return setError('Veuillez remplir tous les champs');
    setLoading(true);
    setError('');
    try {
      const result = await login(email, password);
      
      // التحقق من العمر (إذا كان أقل من 18 يمنع الدخول)
      if (result.user && result.user.age < 18) {
        setError('❌ Désolé, vous devez avoir au moins 18 ans pour utiliser Chatalgerie');
        setLoading(false);
        return;
      }
      
      alert(`✅ Bienvenue ${result.user.name}`);
      onLogin(result.user);
    } catch (err) {
      setError(err.message || 'Erreur de connexion');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <LanguageSwitcher />
        <h1 style={styles.title}>💕 Chatalgerie</h1>
        <p style={styles.subtitle}>Trouvez l'amour en Algérie ❤️</p>
        <p style={styles.ageWarning}>⚠️ Réservé aux +18 ans</p>
        <input type="email" placeholder="📧 Email" value={email} onChange={(e) => setEmail(e.target.value)} style={styles.input} />
        <input type="password" placeholder="🔒 Mot de passe" value={password} onChange={(e) => setPassword(e.target.value)} style={styles.input} />
        {error && <p style={styles.error}>{error}</p>}
        <button onClick={handleLogin} style={styles.button}>{loading ? '⏳...' : '💕 Se connecter'}</button>
        <p style={styles.link} onClick={switchToSignup}>✨ Créer un compte ✨</p>
      </div>
    </div>
  );
}

const styles = {
  container: { display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '100vh', background: 'linear-gradient(135deg, #FFB6C1, #87CEEB)', padding: 20 },
  card: { backgroundColor: 'white', padding: 40, borderRadius: 24, width: '100%', maxWidth: 400, textAlign: 'center' },
  title: { fontSize: '2.5rem', background: 'linear-gradient(45deg, #FF69B4, #4A90D9)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' },
  subtitle: { color: '#888', marginBottom: 5 },
  ageWarning: { color: '#FF1493', fontSize: '0.9rem', fontWeight: 'bold', marginBottom: 15 },
  input: { width: '100%', padding: 12, margin: '10px 0', borderRadius: 12, border: '2px solid #ddd', fontSize: '1rem', boxSizing: 'border-box' },
  button: { width: '100%', padding: 14, background: 'linear-gradient(45deg, #FF6B6B, #FF1493)', color: 'white', border: 'none', borderRadius: 12, fontSize: '1.2rem', fontWeight: 'bold', cursor: 'pointer' },
  link: { color: '#4A90D9', cursor: 'pointer', marginTop: 10 },
  error: { color: 'red', fontSize: '0.9rem' },
};

export default Login;
